import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting input to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input is too long. Please enter a name with 10 characters or less.");
            return;
        }

        char[] buffer = new char[10];

        // Copy input string into buffer
        name.getChars(0, Math.min(name.length(), 10), buffer, 0);

        System.out.println("Hello, " + String.valueOf(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
